--!strict
local InventoryService = {}
local inventories: {[Player]: {string}} = {}
function InventoryService:Init() inventories = {} end
function InventoryService:AddItem(player: Player, itemId: string)
	local inv = inventories[player] or {}
	table.insert(inv, itemId)
	inventories[player] = inv
end
function InventoryService:GetItems(player: Player): {string}
	return inventories[player] or {}
end
return InventoryService
